package main

import (
	"fmt"
	"math/rand"
)

func ri(inf, sup int) float64 {
	return float64(rand.Intn(sup-inf+1) + inf)
}

func gelo(pen *Pen, dist float64, nivel int){
	if nivel == 0 || dist < 2 {
        return
    }


    for range 5 {
        pen.Walk(dist)

            gelo(pen, dist * 0.35, nivel - 3)

        pen.Walk(-dist)
        pen.Right(72)   

    }

}


func rotacao(pen *Pen, dist float64){
	if dist < 1 {
        return
    }


    r := float64(int(dist*1.5) % 256)
    g := float64(int(dist*0.5) % 256)
    b := float64(255 - (int(dist) % 256))


    pen.SetRGB(r, g, b)

    pen.Walk(dist)
    pen.Right(90)


    rotacao(pen, dist - 4)

}
func trigo(pen *Pen, dist float64){
	if dist < 5 {
		return
	}

	pen.SetLineWidth(dist/35)
	pen.Walk(dist)
	trigo(pen, dist * 0.25)

	pen.Left(35)
	trigo(pen, dist * 0.5)
	pen.Right(35)

	pen.Right(35)
	trigo(pen, dist * 0.5)
	pen.Left(35)

	pen.Left(4)
	trigo(pen, dist * 0.3)
	pen.Right(4)

	pen.Right(4)
	trigo(pen, dist * 0.3)
	pen.Left(4)	


	trigo(pen, dist * 0.8)

	pen.Walk(-dist)

}
func triangulo(pen *Pen, tamanho float64, nivel int ){
	if nivel == 0{
		return
	}
	for range 3{
		pen.Walk(tamanho)
		pen.Left(120)
	}

	metade := tamanho/2

	triangulo(pen, metade, nivel-1)

	pen.Walk(metade)
	triangulo(pen, metade, nivel-1)

	pen.Left(120)
    pen.Walk(metade)
    pen.Right(120)
    triangulo(pen, metade, nivel-1)

	pen.Right(120)
    pen.Walk(metade)
    pen.Left(120)

}
func circulos(pen *Pen, raio float64, nivel int){
	if nivel == 0 {
		return
	}
	pen.DrawCircle(raio)

	for range 6 {
		pen.Right(60)

		pen.Up()
		pen.Walk(raio)
		pen.Down()

		pen.Right(90)

		circulos(pen, raio*0.33, nivel-1)

		pen.Up()
		pen.Left(90)
		pen.Walk(-raio)
		pen.Down()
	}
}
func arvere(pen *Pen, dist float64) {
	if dist < 10 {
		if ri(0, 50) == 0 {
			pen.SetRGB(255, 0, 0)
			pen.FillCircle(10)
		}
		return
	}
	ang_dir := ri(10, 40)
	ang_esq := ri(10, 40)

	pen.SetLineWidth(dist / 5)
	pen.SetRGB(0, 0, 0)
	pen.Walk(dist)
	pen.Right(ang_dir)
	arvere(pen, dist*(ri(80, 85)/100))
	pen.Left(ang_dir + ang_esq)
	arvere(pen, dist*(ri(80, 85)/100))
	pen.Right(ang_esq)
	pen.SetRGB(0, 0, 0)
	pen.Walk(-dist)
}

func main() {
	pen := NewPen(800, 800)
	pen.SetHeading(0)
	pen.SetPosition(400, 400)
	gelo(pen, 200, 2)

	pen.SavePNG("tree.png")
	fmt.Println("PNG file created successfully.")
}
